import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");

        String userInput = scanner.nextLine(); // Use nextLine() instead of next() to read the entire line

        char[] buffer = new char[10];

        int length = Math.min(userInput.length(), buffer.length); // Limit input length to buffer size
        userInput.getChars(0, length, buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
